import{_ as a,o,c as d,as as c}from"./chunks/framework.Dt0DMeWU.js";const m=JSON.parse('{"title":"主板","description":"","frontmatter":{},"headers":[],"relativePath":"other/计算机硬件/3-主板.md","filePath":"other/计算机硬件/3-主板.md","lastUpdated":1775485159000}'),t={name:"other/计算机硬件/3-主板.md"};function i(r,e,n,l,h,s){return o(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="主板" tabindex="-1">主板 <a class="header-anchor" href="#主板" aria-label="Permalink to &quot;主板&quot;">​</a></h1><h2 id="版型" tabindex="-1">版型 <a class="header-anchor" href="#版型" aria-label="Permalink to &quot;版型&quot;">​</a></h2><blockquote><p>通常高端主板做大版,中端主板做中板,低端主板做小板的产品思路.</p></blockquote><h3 id="atx" tabindex="-1"><code>ATX</code> <a class="header-anchor" href="#atx" aria-label="Permalink to &quot;`ATX`&quot;">​</a></h3><p><img src="https://img.xbin.cn/images/2023/07/28-14-19-604d50.png" alt=""></p><h3 id="matx" tabindex="-1"><code>MATX</code> <a class="header-anchor" href="#matx" aria-label="Permalink to &quot;`MATX`&quot;">​</a></h3><p><img src="https://img.xbin.cn/images/2023/07/28-14-20-2a3e6c.png" alt=""></p><h3 id="itx" tabindex="-1"><code>ITX</code> <a class="header-anchor" href="#itx" aria-label="Permalink to &quot;`ITX`&quot;">​</a></h3><p><img src="https://img.xbin.cn/images/2023/07/28-14-21-680d76.png" alt=""></p><h2 id="主板等级" tabindex="-1">主板等级 <a class="header-anchor" href="#主板等级" aria-label="Permalink to &quot;主板等级&quot;">​</a></h2><h3 id="intel-芯片组" tabindex="-1"><code>intel</code> 芯片组 <a class="header-anchor" href="#intel-芯片组" aria-label="Permalink to &quot;`intel` 芯片组&quot;">​</a></h3><p>简单来说，<code>intel</code> 芯片组系列主板主要有：<code>X</code>、<code>Z</code>、<code>B</code>、<code>H</code> 四个等级。从高到低分别代表主板的性能高低级别，也就是每个主板型号前面的英文字母。</p><p><code>X</code> 是代表最高旗舰等级的主板型号，是主板中的最高端产品，性能好质量好，但是价格不菲。主要代表主板型号有 <code>X299</code>，一般搭配的 <code>CPU</code> 也十分高端，一般的普通用户根本用不上。</p><p><code>Z</code> 是代表高端级别的主板型号，是主流主板型号中的高性能主板，不仅支持超频，而且支持内存频率也高一些，比较适合一些高级游戏玩家选用。</p><p><code>B</code> 是代主流级别的主板型号，也是大多数电脑用户的主板选择，使用比较广泛性价比最高，不支持超频，一般酷睿不带 <code>K</code> 的处理器都是上 <code>B</code> 系列主板,这种主板完全可以满足大众需求，性价比高，大家配电脑可以考虑。</p><p><code>H</code> 是代表入门级级别的主板型号，性能低价格比较便宜一些，同样不支持超频，一般建议搭配 <code>intel</code> 赛扬、奔腾级别的处理器,日常家用办公的用户选择。</p><h3 id="amd-芯片组" tabindex="-1"><code>AMD</code> 芯片组 <a class="header-anchor" href="#amd-芯片组" aria-label="Permalink to &quot;`AMD` 芯片组&quot;">​</a></h3><p><code>MD</code> 芯片组系列主板有 <code>X</code>、<code>B</code>、<code>A</code> 三个等级，分别代表该系列主板型号的的性能高低，命名规则基本与 <code>intel</code> 类似。</p><p>其中 <code>X</code> 也是代表最高端系列主板，支持超频，性能极极佳，但是价格也是比较贵。例如 <code>X570</code>、<code>X470</code>、<code>X370</code> 三个型号的主板，一般搭配锐龙 <code>R7</code> 和 <code>R9</code> 的高端 <code>CPU</code> 处理器。</p><p><code>B</code> 则是代表定位中端主流级别的主板，也是大部分发电脑用户的最佳选择。<code>AMD</code> 还算是比较良心的商家，相几乎所有的锐龙处理器都支持超频。而主流级别的主板也能够支持超频，例如 <code>B550</code>、<code>B450</code> 主板。</p><p><code>A</code> 则是代表定位入门级别的主板，不支持超频，性能一般价格也比较便宜，一般适合日常家用办公的普通电脑用户。例如 <code>A420</code> 和 <code>A320</code> 主板。</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>简而言之，不管是 <code>intel</code> 主板还是 <code>AMD</code> 主板芯片组，都是分有性能高低等级的。一般型号开头的英文字母，就代表了该主板芯片组的等级高低，不同等级的芯片组搭配 <code>CPU</code> 也有所不同的。</p><p><img src="https://img.xbin.cn/images/2023/07/28-14-52-1927af.png" alt=""></p><h2 id="超频" tabindex="-1">超频 <a class="header-anchor" href="#超频" aria-label="Permalink to &quot;超频&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/07/28-14-37-3ad3c0.png" alt=""></p><h2 id="选择建议" tabindex="-1">选择建议 <a class="header-anchor" href="#选择建议" aria-label="Permalink to &quot;选择建议&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/07/28-14-38-e6d70b.png" alt=""></p>',28)])])}const b=a(t,[["render",i]]);export{m as __pageData,b as default};
